#include<bits/stdc++.h>
using namespace std;

int main(void){
    int n,m;
	cin>>n>>m;
    int dp[n+1][m+1];
	for(int i=1;i<=n;i++)dp[i][1]=1;
	for(int j=1;j<=m;j++)dp[1][j]=1;
	for(int i=2;i<=n;i++){
		for(int j=2;j<=m;j++){
			if(!(i&1)&&!(j&1))dp[i][j]=0;
			else dp[i][j]=dp[i-1][j]+dp[i][j-1];
		}
	}
	cout<<dp[n][m]; 
	return false;
}
